import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

function Register() {
    const [firstName, setFirstName] = useState('');
    const [lastName, setLastName] = useState('');
    const [email, setEmail] = useState('');
    const [phone, setPhone] = useState('');
    const [password, setPassword] = useState('');
    const [error, setError] = useState('');
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await axios.post('http://192.168.66.59:5000/api/auth/register', { firstName, lastName, email, phone, password });
            navigate('/login');
        } catch (err) {
            setError('Registration failed. Please try again.');
        }
    };
       const navigateToLogin = () => {
        navigate('/login');
    };

    return (
        <div>
            <h1>Регистрация</h1>
            <form onSubmit={handleSubmit}>
                <input type="text" placeholder="Имя" value={firstName} onChange={(e) => setFirstName(e.target.value)} />
                <input type="text" placeholder="Фамилия" value={lastName} onChange={(e) => setLastName(e.target.value)} />
                <input type="email" placeholder="Почта" value={email} onChange={(e) => setEmail(e.target.value)} />
                <input type="phone" placeholder="Телефон" value={phone} onChange={(e) => setPhone(e.target.value)} />
                <input type="password" placeholder="Пароль" value={password} onChange={(e) => setPassword(e.target.value)} />
                <button type="submit">Зарегистрировать</button>
            </form>
            {error && <p>{error}</p>}
            <p>
 Уже зарегистрированы?<button onClick={navigateToLogin}> Войти в учетную запись</button>
            </p>

        </div>
    );
}

export default Register;
